import React from 'react'
import ProductCard from '@/app/components/user components/Store/ProductCard'
import { getProduct } from "@/api_call/api";

export default async function page({params,searchParams}) {
    const category_promise = await params;
    const searchParamsPromise = await searchParams  ;
    const brand_slug = searchParamsPromise.brand_slug || null 
    const category_slug = category_promise.slug || null
  const Products_res = await  getProduct({status:true, category_slug :category_slug,brand_slug})
  const products = Products_res?.data;
  // const iamgePath = Products_res?.data?.meta;
  return (
    <div className='grid grid-cols-3 gap-3 space-y-3'>
      {
              products?.map((items)=>{
                return(
                  <ProductCard key={items._id} items = {items} />
                )
              })
            }
    </div>
  )
}

